/**
 * Strategise for Personal Bests - Header/Branding Icon Component
 * 
 * This file contains the Base64-encoded icon used for:
 *   - The login screen branding image
 *   - The WiseWhaleLogo component throughout the app
 *
 * Usage: Include this script in your HTML before the elements that need it.
 *        Access the icon data URL via: window.STRATEGISE_HEADER_ICON
 */

(function() {
    // The Base64-encoded header/branding icon (large PNG)
    const HEADER_ICON_BASE64 = "";

    // Expose the full data URL globally for use in img src attributes
    window.STRATEGISE_HEADER_ICON = 'data:image/png;base64,' + HEADER_ICON_BASE64;
})();
